async (params, browser) => {
  // Open stock news page
  await browser.open(`https://finance.yahoo.com/quote/${params.symbol}/news/`)

  // Wait for news articles to load
  await browser.waitForSelector('[class*=\'news\'] a, [class*=\'stream\'] li, [data-testid=\'news-stream\'] a, article', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load more news
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Extract news articles
  const news_data = await browser.evaluate(`const articles = []; const articleEls = document.querySelectorAll('[data-testid="news-stream"] li, [class*="stream"] li, [class*="news-item"], article, [class*="js-stream-content"] li'); for (let i = 0; i < Math.min(articleEls.length, 15); i++) { const el = articleEls[i]; const titleEl = el.querySelector('h3, h2, [class*="title"] a, a[class*="title"]'); const linkEl = el.querySelector('a[href*="/news/"], a[href*="finance.yahoo.com"], a'); const summaryEl = el.querySelector('p, [class*="summary"], [class*="description"]'); const sourceEl = el.querySelector('[class*="source"], [class*="provider"], span[class*="publishing"]'); const timeEl = el.querySelector('time, [class*="time"], [class*="date"], [class*="ago"]'); const imgEl = el.querySelector('img'); if (titleEl) { articles.push({ title: titleEl.textContent.trim(), url: linkEl ? linkEl.href : '', summary: summaryEl ? summaryEl.textContent.trim().substring(0, 500) : '', source: sourceEl ? sourceEl.textContent.trim() : '', time: timeEl ? timeEl.textContent.trim() : '', image: imgEl ? imgEl.getAttribute('src') : '' }); } } return { symbol: '' + params.symbol + '', article_count: articles.length, articles: articles, url: window.location.href }`)

  return news_data
}
